import questions from "../Questions.json";
import QuestionCard from "../QuestionCard";
import Btn_NextQuestion from '../Btn_NextQuestion';
import React, { useState } from 'react';
import { Link, Navigate, redirect } from "react-router-dom";

import { setAnswer, getAnswerValue } from "../AppState";

export default function QuestionContainer () {
  const [q_number, setNumber] = useState(0);
  const [show, setShow] = React.useState(true);
  const [showAlert, setShowAlert] = React.useState(false);
  var nrOfQuestions = questions.questions.length;
  var btn_next =<Btn_NextQuestion onClick={()=> handle_answer()} ></Btn_NextQuestion>; 
 
  var ar_questions=[];
  questions.questions.forEach( question => {
    ar_questions.push(<QuestionCard params={question} ></QuestionCard>)
  });

  const handle_answer = () => {
    
    var _checked_answer =getCheckedAnswer();
    if(_checked_answer != -1)
    {setShowAlert(false);
      setAnswer(q_number,{value:_checked_answer, data:questions.questions[q_number]});
      if(q_number < nrOfQuestions-1){
        setNumber(q_number+1);
      }else{
        setNumber(q_number+1);
        setShow(false);
      }
    }
    else{ setShowAlert(true);}
   

   
   }

   const getCheckedAnswer = () => {
    if(document.getElementById({q_number}&&"inlineRadio1").checked){return 0;}
    else if(document.getElementById({q_number}&&"inlineRadio2").checked){return 1;}
    else if(document.getElementById({q_number}&&"inlineRadio3").checked){return 2;}
    else if(document.getElementById({q_number}&&"inlineRadio4").checked){return 3;}
    else{return -1;}
   }
return(
  <div>
  {ar_questions[q_number]}
   {show ? btn_next: <Navigate replace to="/results"></Navigate>}
   {showAlert ? <div class="alert alert-warning" role="alert">
  Please chose an answer from the list above!
</div>:null}
 
  </div>
)
   
  
}
